// External declarations from unified_enclave.c
extern "C" {
    typedef struct {
        int hw_type;
        void* enclave_context;
        int initialized;
    } unified_enclave_t;

    int sgx_init_enclave(unified_enclave_t* enclave);
    int sgx_destroy_enclave(unified_enclave_t* enclave);
}

// SGX Enclave ID
sgx_enclave_id_t global_eid = 0;

// Initialize SGX enclave
extern "C" int sgx_init_enclave(unified_enclave_t* enclave) {
    sgx_status_t ret = SGX_ERROR_UNEXPECTED;

    // Create enclave
    ret = sgx_create_enclave("enclave.signed.so", SGX_DEBUG_FLAG, NULL, NULL, &global_eid, NULL);
    if (ret != SGX_SUCCESS) {
        std::cerr &lt;&lt; "Failed to create SGX enclave: " &lt;&lt; ret &lt;&lt; std::endl;
        return -1;
    }

    enclave-&gt;enclave_context = (void*)global_eid;
    enclave-&gt;initialized = 1;

    std::cout &lt;&lt; "SGX enclave initialized successfully" &lt;&lt; std::endl;
    return 0;
}

// Destroy SGX enclave
extern "C" int sgx_destroy_enclave(unified_enclave_t* enclave) {
    if (global_eid == 0) return -1;

    sgx_status_t ret = sgx_destroy_enclave(global_eid);
    if (ret != SGX_SUCCESS) {
        std::cerr &lt;&lt; "Failed to destroy SGX enclave: " &lt;&lt; ret &lt;&lt; std::endl;
        return -1;
    }

    global_eid = 0;
    enclave-&gt;initialized = 0;
    enclave-&gt;enclave_context = NULL;

    std::cout &lt;&lt; "SGX enclave destroyed successfully" &lt;&lt; std::endl;
    return 0;
}

